use strict;
use warnings;
use CAM::PDF;

# Path to the PDF file
my $pdf_path = 'path/to/your/file.pdf';

# Open the PDF file
my $pdf = CAM::PDF->new($pdf_path) or die "Could not open PDF file: $!";

